class Solution:
 def solve(self, k, a):
 n = len(a)
  dp = [0] * (n + 1)
  dp[0] = 0
  for i in range(1, n + 1):
    max_val = float('-inf')
    for j in range(1, min(i, k) + 1):
      max_val = max(max_val, a[i - j] + dp[j])
    dp[i] = max_val
  return dp[n]

